schema.input:
z.object({
  event: z.string(),
  action: z.string().optional(),
  pull_request: z.object({
    number: z.number()
  }).optional(),
  issue: z.object({
    number: z.number(),
    pull_request: z.unknown().optional()
  }).optional(),
  comment: z.object({
    id: z.number(),
    body: z.string(),
    user: z.object({
      login: z.string()
    })
  }).optional(),
  repository: z.object({
    owner: z.object({
      login: z.string()
    }),
    name: z.string()
  }).optional()
})

schema.output:
z.object({
  ok: z.boolean(),
  action: z.string().optional(),
  error: z.string().optional(),
  pr: z.number().optional()
})
